 * Pure JS, no Phaser dependency. Sprite/label references are set externally.
 */

const TILE_SIZE = 48;

// ─── A* pathfinding ───────────────────────────────────────────────────────────

function heuristic(ax, ay, bx, by) {
  return Math.abs(ax - bx) + Math.abs(ay - by);
}

